id" left join "catalog"."bundle" on "catalog"."bundle"."project_id" = "catalog"."product"."project_id" AND "catalog"."bundle"."product_id" = "catalog"."product"."id" where "catalog"."product"."kind" = 'BUNDLE');--> statement-breakpoint
